  design: { label: "GoF Design Patterns", color: "#B7410E", bg: "#FBE9E7" },
  api: { label: "API & Security", color: "#1A5276", bg: "#D6EAF8" },
  ai: { label: "AI / LLM / Agentic / GenAI", color: "#6C3483", bg: "#F5EEF8" },
  cloud: { label: "Cloud & DevOps", color: "#1E8449", bg: "#E8F8F5" },
